import json

second_half_path = locals()['var_functions.query_db:8']

with open(second_half_path, 'r') as f:
    second_half_patents = json.load(f)

# Function to extract CPC codes and get level 4 codes
def extract_cpc_codes(cpc_str):
    try:
        return json.loads(cpc_str)
    except:
        return []

def get_level4_code(full_code):
    if not full_code or '/' not in full_code:
        return None
    main, subgroup = full_code.split('/')
    if len(subgroup) >= 2:
        return f"{main}/{subgroup[:2]}"
    return f"{main}/{subgroup}"

# Count CPC level 4 occurrences
cpc_counts = {}
for patent in second_half_patents:
    cpc_items = extract_cpc_codes(patent['cpc'])
    for item in cpc_items:
        if 'code' in item:
            level4 = get_level4_code(item['code'])
            if level4:
                cpc_counts[level4] = cpc_counts.get(level4, 0) + 1

# Get top 25 most frequent CPC level 4 codes
top_cpc = sorted(cpc_counts.items(), key=lambda x: x[1], reverse=True)[:25]

print('Top CPC Level 4 codes by frequency:')
for code, count in top_cpc:
    print(f"  {code}: {count}")

result_data = {
    'total_patents': len(second_half_patents),
    'unique_level4_codes': len(cpc_counts),
    'top_level4_codes': top_cpc
}

print('\n__RESULT__:')
print(json.dumps(result_data, default=str))

